test_cases.assertion_pseudocode:
// Test with non-existent team
response = POST('/api/v1/workspaces', body={slug:'bad-team-ws', git_url:'https://github.com/org/repo.git', team_id:'nonexistent-team'})
assert response.status == 400
assert response.body.error.code == 400

// Test with inactive team
// Precondition: insert inactive team 'inactive-team' into teams table
response2 = POST('/api/v1/workspaces', body={slug:'inactive-team-ws', git_url:'https://github.com/org/repo.git', team_id:'inactive-team'})
assert response2.status == 400
assert response2.body.error.code == 400

// Test as owner
response = GET('/api/v1/workspaces/target-ws', headers={'Authorization':'Bearer af_key_<user001_key>'})
assert response.status == 200
assert response.body.slug == 'target-ws'
for field in ['id','slug','git_url','branch','team_id','owner_user_id','created_at','updated_at']:
  assert field in response.body

// Test as admin
response2 = GET('/api/v1/workspaces/target-ws', headers={'Authorization':'Bearer af_at_<admin_token>'})
assert response2.status == 200

// Empty string normalized to null
resp1 = POST('/api/v1/workspaces/label-ws/tokens', body={label:''})
assert resp1.status == 201
assert resp1.body.label == null

// Omitted label is null
resp2 = POST('/api/v1/workspaces/label-ws/tokens', body={})
assert resp2.body.label == null

// Non-empty label stored as-is
resp3 = POST('/api/v1/workspaces/label-ws/tokens', body={label:'my-label'})
assert resp3.body.label == 'my-label'

// Expired token
resp1 = GET('/api/v1/workspaces/auth-check-ws', headers={'Authorization':'Bearer af_wt_<expired_token>'})
assert resp1.status == 401

// Revoked token
resp2 = GET('/api/v1/workspaces/auth-check-ws', headers={'Authorization':'Bearer af_wt_<revoked_token>'})
assert resp2.status == 401

// Admin cannot create workspace
resp = POST('/api/v1/workspaces', headers={'Authorization':'Bearer af_at_<admin>'})
assert resp.status == 403

// Admin can list all workspaces
resp = GET('/api/v1/workspaces', headers={'Authorization':'Bearer af_at_<admin>'})
assert resp.status == 200

// Workspace token cannot list workspaces
resp = GET('/api/v1/workspaces', headers={'Authorization':'Bearer af_wt_<token>'})
assert resp.status == 403

// Workspace token can get own workspace
resp = GET('/api/v1/workspaces/<scoped_slug>', headers={'Authorization':'Bearer af_wt_<token>'})
assert resp.status == 200

// Workspace token cannot create tokens
resp = POST('/api/v1/workspaces/<scoped_slug>/tokens', headers={'Authorization':'Bearer af_wt_<token>'})
assert resp.status == 403

response = POST('/api/v1/workspaces', body={slug:'no-content-type-ws', git_url:'https://github.com/org/repo.git'}, headers={'Authorization':'Bearer af_key_<key>'})
// NOTE: no Content-Type header set
assert response.status == 201

edge_case_tests.assertion_pseudocode:
response = POST('/api/v1/workspaces', body={slug:'empty-branch-ws', git_url:'https://github.com/org/repo.git', branch:''})
// Implementation must choose: store as '' or normalize to null
// Assert the documented behavior:
assert response.status in [200, 201, 400]  // 400 only if empty string is explicitly rejected
if response.status == 201:
  assert response.body.branch == '' or response.body.branch == null  // document which

// Create 10 tokens with same label first
for i in range(10):
  r = POST('/api/v1/workspaces/many-tokens-ws/tokens', body={label:'shared-label'})
  assert r.status == 201

// 11th token with same label also succeeds
response = POST('/api/v1/workspaces/many-tokens-ws/tokens', body={label:'shared-label'})
assert response.status == 201
// Verify 11 tokens exist
count = db.query('SELECT COUNT(*) FROM workspace_tokens WHERE workspace_id = ?', workspace_id)
assert count == 11
